  /**
   * Compute a single MetricSummary by aggregating repository data for the
   * queried period and an equally-sized preceding period.
   */
  private async computeMetricSummary(
    metricType: MetricType,
    query: AnalyticsQuery,
  ): Promise<MetricSummary> {
    const currentValue = this.computeMetricValue(metricType, query.startDate, query.endDate);

    const periodMs = query.endDate.getTime() - query.startDate.getTime();
    const prevStart = new Date(query.startDate.getTime() - periodMs);
    const prevEnd = query.startDate;
    const previousValue = this.computeMetricValue(metricType, prevStart, prevEnd);

    let changePercent = 0;
    if (previousValue !== 0) {
      changePercent = ((currentValue - previousValue) / previousValue) * 100;
    }

    let trend: 'up' | 'down' | 'flat' = 'flat';
    if (changePercent > 0) trend = 'up';
    else if (changePercent < 0) trend = 'down';

    return { metricType, currentValue, previousValue, changePercent, trend };
  }

  /**
   * Compute the raw numeric value for a metric within a date range.
   */
  private computeMetricValue(metricType: MetricType, start: Date, end: Date): number {
    switch (metricType) {
      case 'revenue': {
        const orders = this.getOrdersInRange(start, end);
        return orders.reduce((sum, o) => sum + o.total, 0);
      }
      case 'orders': {
        return this.getOrdersInRange(start, end).length;
      }
      case 'users': {
        const users = this.userRepository.findAll(
          (u) => u.createdAt >= start && u.createdAt < end,
        );
        return users.length;
      }
      case 'average-order-value': {
        const orders = this.getOrdersInRange(start, end);
        if (orders.length === 0) return 0;
        const revenue = orders.reduce((sum, o) => sum + o.total, 0);
        return revenue / orders.length;
      }
    }
  }

  /**
   * Fetch orders whose createdAt falls within [start, end).
   */
  private getOrdersInRange(start: Date, end: Date) {
    return this.orderRepository.findAll(
      (o) => o.createdAt >= start && o.createdAt < end,
    );
  }

  /**
   * Build a time series for the given metric and granularity.
   */
  private async getTimeSeries(
    query: MetricsQuery,
  ): Promise<TimeSeriesPoint[]> {
    const buckets = this.generateBuckets(query.startDate, query.endDate, query.granularity ?? 'day');
    return buckets.map((bucket) => ({
      timestamp: bucket.start,
      value: this.computeMetricValue(query.metricType, bucket.start, bucket.end),
      label: bucket.label,
    }));
  }

  /**
   * Generate time buckets from start to end using the given granularity.
   */
  private generateBuckets(
    start: Date,
    end: Date,
    granularity: TimeGranularity,
  ): { start: Date; end: Date; label: string }[] {
    const buckets: { start: Date; end: Date; label: string }[] = [];
    let current = new Date(start);

    while (current < end) {
      const bucketEnd = this.advanceDate(current, granularity);
      const clampedEnd = bucketEnd > end ? end : bucketEnd;
      buckets.push({
        start: new Date(current),
        end: clampedEnd,
        label: this.formatBucketLabel(current, granularity),
      });
      current = bucketEnd;
    }

    return buckets;
  }

  /**
   * Advance a date by one unit of the given granularity.
   */
  private advanceDate(date: Date, granularity: TimeGranularity): Date {
    const next = new Date(date);
    switch (granularity) {
      case 'hour':
        next.setTime(next.getTime() + 60 * 60 * 1000);
        break;
      case 'day':
        next.setDate(next.getDate() + 1);
        break;
      case 'week':
        next.setDate(next.getDate() + 7);
        break;
      case 'month':
        next.setMonth(next.getMonth() + 1);
        break;
    }
    return next;
  }

  /**
   * Format a human-readable label for a time bucket.
   */
  private formatBucketLabel(date: Date, granularity: TimeGranularity): string {
    switch (granularity) {
      case 'hour':
        return `${date.getUTCHours()}:00`;
      case 'day':
        return date.toISOString().slice(0, 10);
      case 'week':
        return `Week of ${date.toISOString().slice(0, 10)}`;
      case 'month':
        return `${date.getUTCFullYear()}-${String(date.getUTCMonth() + 1).padStart(2, '0')}`;
    }
  }

  /**
   * Count orders grouped by status for the queried date range.
   */
  private async getOrderStatusBreakdown(
    query: AnalyticsQuery,
  ): Promise<OrderStatusBreakdown[]> {
    const orders = this.getOrdersInRange(query.startDate, query.endDate);
    const total = orders.length;
    if (total === 0) return [];

    const counts = new Map<string, number>();
    for (const order of orders) {
      counts.set(order.status, (counts.get(order.status) ?? 0) + 1);
    }

    return Array.from(counts.entries()).map(([status, count]) => ({
      status,
      count,
      percent: (count / total) * 100,
    }));
  }

  /**
   * Return the top N users by revenue in the queried date range.
   */
  private async getTopUsers(
    query: AnalyticsQuery,
    limit: number = 10,
  ): Promise<TopUser[]> {
    const orders = this.getOrdersInRange(query.startDate, query.endDate);

    const userStats = new Map<string, { totalOrders: number; totalRevenue: number }>();
    for (const order of orders) {
      const stats = userStats.get(order.userId) ?? { totalOrders: 0, totalRevenue: 0 };
      stats.totalOrders += 1;
      stats.totalRevenue += order.total;
      userStats.set(order.userId, stats);
    }

    const results: TopUser[] = [];
    for (const [userId, stats] of userStats) {
      const user = this.userRepository.findById(userId);
      results.push({
        userId,
        userName: user?.name ?? 'Unknown',
        totalOrders: stats.totalOrders,
        totalRevenue: stats.totalRevenue,
      });
    }

    results.sort((a, b) => b.totalRevenue - a.totalRevenue);
    return results.slice(0, limit);
  }
}

